"""
Time-sliced generation system for managing resource usage.
Allows larger models to run on constrained hardware by breaking generation into smaller chunks.
"""
import asyncio
import time
import psutil
from typing import Optional, Dict, Any, AsyncGenerator
from dataclasses import dataclass
from .runtime_profiles import ResourceProfile, resource_manager

@dataclass
class TimeBudget:
    """Tracks time budget for generation tasks"""
    total_seconds: float
    started_at: float
    warning_threshold: float = 0.8  # Warn at 80% of budget

    @property
    def elapsed(self) -> float:
        """Time elapsed since start"""
        return time.time() - self.started_at

    @property
    def remaining(self) -> float:
        """Time remaining in budget"""
        return max(0, self.total_seconds - self.elapsed)

    @property
    def progress(self) -> float:
        """Progress as fraction (0.0 to 1.0)"""
        return min(1.0, self.elapsed / self.total_seconds)

    @property
    def is_warning(self) -> bool:
        """True if we've exceeded warning threshold"""
        return self.progress >= self.warning_threshold

    @property
    def is_exceeded(self) -> bool:
        """True if budget is exceeded"""
        return self.progress >= 1.0

@dataclass
class GenerationState:
    """State of an ongoing generation"""
    tokens_generated: int = 0
    total_slices: int = 0
    current_slice: int = 0
    accumulated_text: str = ""
    last_slice_time: float = 0.0
    memory_at_start: float = 0.0

class TimeSlicedGenerator:
    """
    Manages time-sliced generation to prevent resource overload.
    Breaks generation into small chunks with monitoring and yielding.
    """

    def __init__(self, profile: ResourceProfile):
        self.profile = profile
        self.state = GenerationState()

    async def generate_sliced(self, ollama_client, prompt: str, system_prompt: Optional[str] = None,
                             budget: TimeBudget = None, task_type: str = 'standard') -> AsyncGenerator[str, None]:
        """
        Generate text in time slices, yielding control between chunks.

        Args:
            ollama_client: The OllamaClient instance
            prompt: Input prompt
            system_prompt: Optional system prompt
            budget: Time budget for generation
            task_type: Type of task for optimization

        Yields:
            Chunks of generated text
        """
        if budget is None:
            budget = TimeBudget(total_seconds=30.0, started_at=time.time())

        self.state = GenerationState()
        self.state.memory_at_start = psutil.virtual_memory().percent

        try:
            # Stream generation from Ollama
            async for chunk in ollama_client.stream_generate(prompt, system_prompt, task_type):
                self.state.tokens_generated += len(chunk.split())  # Rough token count
                self.state.accumulated_text += chunk

                # Check if we should yield control
                if self._should_yield(budget):
                    yield chunk
                    await self._yield_control(budget)

                    # Check if we should stop due to budget
                    if self._should_stop(budget):
                        break

                    self.state.current_slice += 1
                else:
                    yield chunk

        except Exception as e:
            # If generation fails, return partial result
            if self.state.accumulated_text:
                yield f"\n\n[Generation stopped due to error: {e}]"
            else:
                raise

    async def generate_single_shot(self, ollama_client, prompt: str, system_prompt: Optional[str] = None,
                                  budget: TimeBudget = None, task_type: str = 'standard') -> str:
        """
        Generate text in single shot with budget monitoring.
        Falls back to sliced generation if budget is tight.
        """
        if budget is None:
            budget = TimeBudget(total_seconds=30.0, started_at=time.time())

        # If we have a generous budget and resources, try single shot
        if budget.total_seconds > 60 and self.profile.level.value >= 75:
            try:
                return await ollama_client.generate(prompt, system_prompt, task_type)
            except asyncio.TimeoutError:
                # Fall back to sliced generation
                pass

        # Use sliced generation
        result = ""
        async for chunk in self.generate_sliced(ollama_client, prompt, system_prompt, budget, task_type):
            result += chunk

        return result

    def _should_yield(self, budget: TimeBudget) -> bool:
        """Check if we should yield control to the event loop"""
        # Yield every N tokens based on profile
        tokens_since_yield = self.state.tokens_generated - (self.state.current_slice * self.profile.step_tokens)

        if tokens_since_yield >= self.profile.step_tokens:
            return True

        # Yield if memory usage is high
        current_memory = psutil.virtual_memory().percent
        if current_memory > 85:  # 85% memory usage
            return True

        # Yield if we're approaching budget warning
        if budget.is_warning and not hasattr(self, '_warned'):
            self._warned = True
            return True

        return False

    def _should_stop(self, budget: TimeBudget) -> bool:
        """Check if we should stop generation entirely"""
        # Stop if budget is exceeded
        if budget.is_exceeded:
            return True

        # Stop if memory usage is critical
        current_memory = psutil.virtual_memory().percent
        if current_memory > 95:  # 95% memory usage
            return True

        return False

    async def _yield_control(self, budget: TimeBudget):
        """Yield control to event loop and apply backpressure"""
        # Sleep based on profile
        if self.profile.slice_sleep_ms > 0:
            await asyncio.sleep(self.profile.slice_sleep_ms / 1000.0)

        # Additional backpressure if memory is high
        current_memory = psutil.virtual_memory().percent
        if current_memory > 80:
            # Progressive backpressure: more sleep as memory increases
            extra_sleep = (current_memory - 80) / 20.0 * 0.1  # Up to 100ms extra
            await asyncio.sleep(extra_sleep)

    def get_progress_info(self, budget: TimeBudget) -> Dict[str, Any]:
        """Get current progress information"""
        current_memory = psutil.virtual_memory().percent

        return {
            'tokens_generated': self.state.tokens_generated,
            'slices_completed': self.state.current_slice,
            'time_elapsed': budget.elapsed,
            'time_remaining': budget.remaining,
            'time_progress': budget.progress,
            'memory_usage_percent': current_memory,
            'memory_change': current_memory - self.state.memory_at_start,
            'is_warning': budget.is_warning,
            'is_exceeded': budget.is_exceeded
        }

    def get_partial_result_message(self, budget: TimeBudget) -> str:
        """Get message to append when returning partial results"""
        if budget.is_exceeded:
            return f"""

[Generation stopped at time limit ({budget.total_seconds:.1f}s). Partial result shown above.]

💡 Suggestions:
- Use `/mode think 15m` for longer generation time
- Use `/settings resources 25` for more conservative resource usage
- Use `/settings resources 75` if you have more powerful hardware"""

        return ""

# Convenience function for easy access
def create_time_slicer(resource_level: int = 50) -> TimeSlicedGenerator:
    """Create a time slicer with specified resource level (25, 50, 75, 100)"""
    profile = resource_manager.get_profile_by_percentage(resource_level)
    return TimeSlicedGenerator(profile)